          <form onSubmit={handleSubmit(onSubmit)} noValidate className="space-y-4">
            <Input
              label="Username"
              type="text"
              autoComplete="username"
              autoFocus
              required
              error={errors.username?.message}
              {...register('username')}
            />

            <Input
              label="Password"
              type="password"
              autoComplete="current-password"
              required
              error={errors.password?.message}
              {...register('password')}
            />

            {/* CAPTCHA challenge */}
            {captcha && (
              <div className="p-3 rounded-md bg-amber-50 border border-amber-200 space-y-2">
                <p className="text-xs text-amber-700 font-medium">
                  Security check required after multiple failed attempts.
                </p>
                <p className="text-sm font-semibold text-amber-900">
                  {captcha.question}
                </p>
                <Input
                  label="Your answer"
                  type="number"
                  required
                  error={errors.captcha_answer?.message}
                  {...register('captcha_answer', { valueAsNumber: true })}
                />
              </div>
            )}

            <Button
              type="submit"
              className="w-full"
              loading={loginPending}
              disabled={loginPending || !!locked}
            >
              Sign in
            </Button>
          </form>

          <p className="text-xs text-slate-400 text-center">
            Sessions expire after 30 minutes of inactivity.
          </p>
        </div>
      </div>
    </div>
  );
}
"}

