  { value: 'moderately_active',  label: 'Moderately Active' },
  { value: 'very_active',        label: 'Very Active'       },
  { value: 'extra_active',       label: 'Extra Active'      },
];

const RANGE_OPTIONS = [
  { value: '7d',  label: 'Last 7 days'  },
