    queryKey: ['metrics', memberId, selectedMetric, range],
    queryFn:  () =>
      metricsApi.getMetrics({
        member_id:   memberId,
        metric_type: selectedMetric,
        range:       range as '7d' | '30d' | '90d' | 'all',
      }),
  });

  // ── Add Metric Entry ────────────────────────────────────────────────────────
  const schema = metricEntrySchema(selectedMetric);
  const metricForm = useForm({
    resolver: zodResolver(schema),
    defaultValues: {
      member_id:   memberId,
      metric_type: selectedMetric,
      entry_date:  new Date().toISOString().slice(0, 10),
    },
  });

  const addMetricMutation = useMutation({
    mutationFn: (values: ReturnType<typeof schema>['_type']) =>
      metricsApi.createMetricEntry(values),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['metrics', memberId] });
      toast.success('Metric entry recorded.');
      setAddMetricOpen(false);
      metricForm.reset();
