    mutationFn: (values: HealthProfileFormValues) =>
      profilesApi.updateProfile(memberId, values),
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['profile', memberId] });
      toast.success('Profile updated.');
      setEditProfileOpen(false);
