              { label: 'Height',        value: profile.height_in ? `${profile.height_in} in` : 'N/A' },
              { label: 'Weight',        value: profile.weight_lbs ? `${profile.weight_lbs} lbs` : 'N/A' },
              { label: 'Activity',      value: profile.activity_level ?? 'N/A' },
