// ── Members Page ──────────────────────────────────────────────────────────────

export function MembersPage() {
  const navigate = useNavigate();

  // The backend doesn't expose a user list endpoint in the spec.
  // Admins/coaches navigate to a member's detail by UUID.
  // For now we show the current user's own profile as the default view.
  const currentUser = useAuthStore((s) => s.user);
  const [selectedMemberId, setSelectedMemberId] = useState<string | null>(
    currentUser?.id ?? null,
  );
  const [searchId, setSearchId] = useState('');

  const handleSearch = () => {
    const trimmed = searchId.trim();
    if (trimmed) setSelectedMemberId(trimmed);
  };

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-slate-900">
            Members &amp; Health Profiles
          </h1>
          <p className="text-sm text-slate-500 mt-0.5">
            View and manage member health data, metrics, and profiles.
          </p>
        </div>
      </div>

      {/* Member lookup */}
      <Card title="Look up member">
        <div className="flex gap-3">
          <Input
            placeholder="Paste member UUID…"
            value={searchId}
            onChange={(e) => setSearchId(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSearch()}
            className="flex-1"
          />
          <Button onClick={handleSearch}>View profile</Button>
        </div>
        {currentUser && (
          <button
            className="mt-2 text-xs text-brand-600 hover:underline"
            onClick={() => setSelectedMemberId(currentUser.id)}
          >
            View my profile ({currentUser.username})
          </button>
        )}
      </Card>

      {/* Member detail */}
      {selectedMemberId && (
        <div>
          <div className="flex items-center gap-2 text-xs text-slate-500 mb-3">
            <span>Member ID:</span>
            <code className="bg-slate-100 px-1.5 py-0.5 rounded text-slate-700">
              {selectedMemberId}
            </code>
          </div>
          <MemberDetail memberId={selectedMemberId} />
        </div>
      )}
    </div>
  );
}
"}

