  entity_id:   z.string().optional(),
  start_date:  z.string().regex(/^\d{4}-\d{2}-\d{2}$/).optional().or(z.literal('')),
  end_date:    z.string().regex(/^\d{4}-\d{2}-\d{2}$/).optional().or(z.literal('')),
});

type FilterFormValues = z.infer<typeof filterSchema>;

