                      {log.actor_id ? `${log.actor_id.slice(0, 8)}…` : '—'}
                    </td>
                    <td className="px-4 py-3 text-xs text-slate-400">
                      {log.ip_address ?? '—'}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Pagination */}
          <div className="flex items-center justify-between">
            <Button
